SELECT SUM(total_electors) AS total_electors
FROM electoral_data
WHERE constituency_code = '0';

SELECT constituency_code
FROM electoral_data
WHERE year = (
    SELECT MAX(year)
    FROM electoral_data
) AND registered_voters = (
    SELECT MAX(registered_voters)
    FROM electoral_data
    WHERE year = (
        SELECT MAX(year)
        FROM electoral_data
    )
);

SELECT constituency_code, AVG(CAST(REPLACE(average_age, ',', '') AS REAL)) AS real_average_age
FROM electoral_data
GROUP BY constituency_code;

SELECT constituency_name 
FROM constituencies 
WHERE constituency_code = '0';

SELECT total_electors, registered_voters
FROM electoral_data
WHERE year = 2023;

SELECT voter_turnout
FROM electoral_data
WHERE constituency_code = '0' AND year = 2022;

SELECT MIN(total_electors) AS min_total_electors
FROM electoral_data
WHERE year = 2023;
